import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.CHeM0PsO.js";const m=JSON.parse('{"title":"ADR-0002: Separate Installation Images from Update Artifacts","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/adrs/0002-install-images-and-update-artifacts.md","filePath":"sovereign-os/adrs/0002-install-images-and-update-artifacts.md"}'),s={name:"sovereign-os/adrs/0002-install-images-and-update-artifacts.md"};function n(o,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-0002-separate-installation-images-from-update-artifacts" tabindex="-1">ADR-0002: Separate Installation Images from Update Artifacts <a class="header-anchor" href="#adr-0002-separate-installation-images-from-update-artifacts" aria-label="Permalink to &quot;ADR-0002: Separate Installation Images from Update Artifacts&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> 2026-07-19<br><strong>Decision owner:</strong> Project creator<br><strong>Related milestone:</strong> <a href="./../roadmap/01-1-update-foundation.html">Appliance Update Foundation</a><br><strong>Related RFC:</strong> <a href="./../rfcs/0014-appliance-update-system.html">RFC-0014</a></p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Writing a new raw disk image replaces the target storage layout and normally erases installed configuration and data. That is acceptable for clean installation and recovery but not for routine updates of an operating household service.</p><p>Pi-hole&#39;s container can be replaced independently when its state is stored outside the container. Sovereign appliance configuration can also be installed into versioned directories and activated atomically. Full operating-system replacement requires a more advanced A/B root-filesystem design.</p><p>The update capability is the highest priority immediately after the Phase 01 image is released.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ul><li>A compressed disk image is the clean-install and recovery artifact.</li><li>Existing installations receive separately packaged, signed update artifacts.</li><li>Application, appliance, and base-OS versions are tracked independently.</li><li>Pi-hole and all valuable user/device state live on a dedicated persistent data partition mounted at <code>/data</code>.</li><li>Phase 01 must establish the data partition and version metadata, but need not implement the updater.</li><li>The first updater is user-triggered and may be command-line based.</li><li>Updates are staged, authenticated, backed up, health checked, journaled, and automatically rolled back when safe.</li><li>Mutable container tags are not supported update inputs.</li><li>Full A/B operating-system updates are a later design; the current layout and updater must preserve that option.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Routine releases do not wipe Pi-hole data or credentials.</li><li>New-install and existing-device delivery can evolve independently.</li><li>Container and appliance rollback become practical.</li><li>Release artifacts can be smaller than complete disk images.</li><li>A dedicated data partition prepares the product for A/B OS updates.</li><li>Users are not forced to reconfigure their routers after every release.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>The project must build and test both installation and update artifacts.</li><li>Signing, key custody, version compatibility, migrations, and rollback become product responsibilities.</li><li>A dedicated data partition complicates the Phase 01 image layout.</li><li>Container rollback may be unsafe after irreversible Pi-hole data migration.</li><li>Base-OS updates remain a separate problem until A/B support exists.</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>A flawed updater can interrupt household DNS.</li><li>Signing-key compromise could authorize malicious releases.</li><li>Power loss may leave a partially staged transaction.</li><li>Insufficient storage may prevent backup or rollback.</li><li>Release image and update artifact may drift if built from different definitions.</li><li>Persistent data may contain sensitive DNS history and secrets.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><h3 id="reflash-for-every-release" tabindex="-1">Reflash for every release <a class="header-anchor" href="#reflash-for-every-release" aria-label="Permalink to &quot;Reflash for every release&quot;">​</a></h3><p>Rejected as the normal update path because it erases state and creates unnecessary setup and recovery work.</p><h3 id="modify-active-files-and-containers-in-place" tabindex="-1">Modify active files and containers in place <a class="header-anchor" href="#modify-active-files-and-containers-in-place" aria-label="Permalink to &quot;Modify active files and containers in place&quot;">​</a></h3><p>Rejected because partial failure is hard to diagnose and roll back.</p><h3 id="implement-a-b-root-filesystems-immediately" tabindex="-1">Implement A/B root filesystems immediately <a class="header-anchor" href="#implement-a-b-root-filesystems-immediately" aria-label="Permalink to &quot;Implement A/B root filesystems immediately&quot;">​</a></h3><p>Deferred because it adds bootloader, partition, storage, health-commit, and recovery complexity before the POC image is proven.</p><h3 id="unattended-automatic-updates-from-the-first-release" tabindex="-1">Unattended automatic updates from the first release <a class="header-anchor" href="#unattended-automatic-updates-from-the-first-release" aria-label="Permalink to &quot;Unattended automatic updates from the first release&quot;">​</a></h3><p>Deferred because manual initiation provides better control and diagnosis while formats and compatibility rules are immature.</p><h2 id="validation-and-revisit-conditions" tabindex="-1">Validation and Revisit Conditions <a class="header-anchor" href="#validation-and-revisit-conditions" aria-label="Permalink to &quot;Validation and Revisit Conditions&quot;">​</a></h2><p>Revisit the design when:</p><ul><li>Phase 01 storage measurements show that a dedicated data partition is impractical;</li><li>Pi-hole migrations prevent safe application rollback;</li><li>base-OS security maintenance requires A/B implementation sooner;</li><li>a selected update framework provides stronger guarantees with less custom code;</li><li>the project introduces additional applications with cross-service migrations.</li></ul>',27)])])}const h=a(s,[["render",n]]);export{m as __pageData,h as default};
